@strawberry.type
class ProductType:
    id: int
    name: str
    description: Optional[str]
    price: float
    stock: int
    created_at: datetime
    seller: Optional[SellerType]
    reviews: list[ReviewType]
    images: list[ImageType]
    categories: list[CategoryType]

    @strawberry.field
    def average_rating(self) -> Optional[float]:
        if not self.reviews:
            return None
        return sum(r.rating for r in self.reviews) / len(self.reviews)

    @strawberry.field
    def review_count(self) -> int:
        return len(self.reviews)


@strawberry.type
class PaginatedProducts:
    items: list[ProductType]
    total_count: int
    has_next_page: bool
    has_previous_page: bool


# --- Conversion helpers ---

def _image_model_to_type(img: ImageModel) -> ImageType:
    return ImageType(
        id=img.id,
        url=img.url,
        alt_text=img.alt_text,
        sort_order=img.sort_order,
    )


def _review_model_to_type(rev: ReviewModel) -> ReviewType:
    return ReviewType(
        id=rev.id,
        author=rev.author,
        content=rev.content,
        rating=rev.rating,
        created_at=rev.created_at,
    )


def _category_model_to_type(cat: CategoryModel) -> CategoryType:
    return CategoryType(
        id=cat.id,
        name=cat.name,
        description=cat.description,
    )


def _seller_model_to_type(seller: SellerModel) -> Optional[SellerType]:
    if seller is None:
        return None
    return SellerType(
        id=seller.id,
        name=seller.name,
        email=seller.email,
        rating=seller.rating or 0.0,
        created_at=seller.created_at,
    )


def _product_model_to_type(product: ProductModel) -> ProductType:
    return ProductType(
        id=product.id,
        name=product.name,
        description=product.description,
        price=float(product.price),
        stock=product.stock,
        created_at=product.created_at,
        seller=_seller_model_to_type(product.seller),
        reviews=[_review_model_to_type(r) for r in product.reviews],
        images=[_image_model_to_type(i) for i in product.images],
        categories=[_category_model_to_type(c) for c in product.categories],
    )


# --- Query ---

@strawberry.type
class Query:
    @strawberry.field
    def product(self, id: int) -> Optional[ProductType]:
        with get_db() as db:
            product = (
                db.query(ProductModel)
                .options(
                    joinedload(ProductModel.seller),
                    joinedload(ProductModel.reviews),
                    joinedload(ProductModel.images),
                    joinedload(ProductModel.categories),
                )
                .filter(ProductModel.id == id)
                .first()
            )
            if not product:
                return None
            return _product_model_to_type(product)

    @strawberry.field
    def products(
        self,
        limit: int = 20,
        offset: int = 0,
        search: Optional[str] = None,
        category_id: Optional[int] = None,
        seller_id: Optional[int] = None,
        min_price: Optional[float] = None,
        max_price: Optional[float] = None,
    ) -> PaginatedProducts:
        limit = min(max(limit, 1), 100)
        offset = max(offset, 0)

        with get_db() as db:
            query = db.query(ProductModel).options(
                joinedload(ProductModel.seller),
                joinedload(ProductModel.reviews),
                joinedload(ProductModel.images),
                joinedload(ProductModel.categories),
            )

            if search:
                safe_search = f"%{search}%"
                query = query.filter(
                    ProductModel.name.ilike(safe_search)
                    | ProductModel.description.ilike(safe_search)
                )

            if category_id is not None:
                query = query.filter(
                    ProductModel.categories.any(CategoryModel.id == category_id)
                )

            if seller_id is not None:
                query = query.filter(ProductModel.seller_id == seller_id)

            if min_price is not None:
                query = query.filter(ProductModel.price >= decimal.Decimal(str(min_price)))

            if max_price is not None:
                query = query.filter(ProductModel.price <= decimal.Decimal(str(max_price)))

            total_count = query.count()
            products = query.offset(offset).limit(limit).all()

            return PaginatedProducts(
                items=[_product_model_to_type(p) for p in products],
                total_count=total_count,
                has_next_page=(offset + limit) < total_count,
                has_previous_page=offset > 0,
            )

    @strawberry.field
    def seller(self, id: int) -> Optional[SellerType]:
        with get_db() as db:
            seller = db.query(SellerModel).filter(SellerModel.id == id).first()
            if not seller:
                return None
            return _seller_model_to_type(seller)

    @strawberry.field
    def sellers(self, limit: int = 20, offset: int = 0) -> list[SellerType]:
        limit = min(max(limit, 1), 100)
        offset = max(offset, 0)
        with get_db() as db:
            sellers = db.query(SellerModel).offset(offset).limit(limit).all()
            return [_seller_model_to_type(s) for s in sellers]

    @strawberry.field
    def category(self, id: int) -> Optional[CategoryType]:
        with get_db() as db:
            cat = db.query(CategoryModel).filter(CategoryModel.id == id).first()
            if not cat:
                return None
            return _category_model_to_type(cat)

    @strawberry.field
    def categories(self) -> list[CategoryType]:
        with get_db() as db:
            cats = db.query(CategoryModel).all()
            return [_category_model_to_type(c) for c in cats]


# --- Mutations ---

@strawberry.input
class CreateProductInput:
    name: str
    description: Optional[str] = None
    price: float
    stock: int = 0
    seller_id: Optional[int] = None
    category_ids: Optional[list[int]] = None


@strawberry.input
class CreateReviewInput:
    product_id: int
    author: str
    content: Optional[str] = None
    rating: int


@strawberry.input
class CreateSellerInput:
    name: str
    email: str


@strawberry.input
class CreateCategoryInput:
    name: str
    description: Optional[str] = None


@strawberry.input
class AddImageInput:
    product_id: int
    url: str
    alt_text: Optional[str] = None
    sort_order: int = 0


@strawberry.type
class Mutation:
    @strawberry.mutation
    def create_product(self, input: CreateProductInput) -> ProductType:
        if input.price < 0:
            raise ValueError("Price cannot be negative")
        if input.stock < 0:
            raise ValueError("Stock cannot be negative")
        if len(input.name.strip()) == 0:
            raise ValueError("Product name cannot be empty")
        if len(input.name) > 255:
            raise ValueError("Product name too long")

        with get_db() as db:
            product = ProductModel(
                name=input.name.strip(),
                description=input.description.strip() if input.description else None,
                price=decimal.Decimal(str(input.price)),
                stock=input.stock,
                seller_id=input.seller_id,
            )

            if input.category_ids:
                categories = (
                    db.query(CategoryModel)
                    .filter(CategoryModel.id.in_(input.category_ids))
                    .all()
                )
                product.categories = categories

            db.add(product)
            db.commit()
            db.refresh(product)
            return _product_model_to_type(product)

    @strawberry.mutation
    def create_review(self, input: CreateReviewInput) -> ReviewType:
        if input.rating < 1 or input.rating > 5:
            raise ValueError("Rating must be between 1 and 5")
        if len(input.author.strip()) == 0:
            raise ValueError("Author name cannot be empty")
        if len(input.author) > 255:
            raise ValueError("Author name too long")

        with get_db() as db:
            product = db.query(ProductModel).filter(ProductModel.id == input.product_id).first()
            if not product:
                raise ValueError("Product not found")

            review = ReviewModel(
                product_id=input.product_id,
                author=input.author.strip(),
                content=input.content.strip() if input.content else None,
                rating=input.rating,
            )
            db.add(review)
            db.commit()
            db.refresh(review)
            return _review_model_to_type(review)

    @strawberry.mutation
    def create_seller(self, input: CreateSellerInput) -> SellerType:
        if len(input.name.strip()) == 0:
            raise ValueError("Seller name cannot be empty")
        if len(input.name) > 255:
            raise ValueError("Seller name too long")
        if len(input.email.strip()) == 0:
            raise ValueError("Email cannot be empty")
        if "@" not in input.email or "." not in input.email.split("@")[-1]:
            raise ValueError("Invalid email format")
        if len(input.email) > 255:
            raise ValueError("Email too long")

        with get_db() as db:
            existing = db.query(SellerModel).filter(SellerModel.email == input.email.strip().lower()).first()
            if existing:
                raise ValueError("A seller with this email already exists")

            seller = SellerModel(
                name=input.name.strip(),
                email=input.email.strip().lower(),
            )
            db.add(seller)
            db.commit()
            db.refresh(seller)
            return _seller_model_to_type(seller)

    @strawberry.mutation
    def create_category(self, input: CreateCategoryInput) -> CategoryType:
        if len(input.name.strip()) == 0:
            raise ValueError("Category name cannot be empty")
        if len(input.name) > 255:
            raise ValueError("Category name too long")

        with get_db() as db:
            existing = db.query(CategoryModel).filter(CategoryModel.name == input.name.strip()).first()
            if existing:
                raise ValueError("A category with this name already exists")

            category = CategoryModel(
                name=input.name.strip(),
                description=input.description.strip() if input.description else None,
            )
            db.add(category)
            db.commit()
            db.refresh(category)
            return _category_model_to_type(category)

    @strawberry.mutation
    def add_image(self, input: AddImageInput) -> ImageType:
        if len(input.url.strip()) == 0:
            raise ValueError("Image URL cannot be empty")
        if len(input.url) > 1024:
            raise ValueError("Image URL too long")
        url_lower = input.url.strip().lower()
        if not (url_lower.startswith("https://") or url_lower.startswith("http://")):
            raise ValueError("Image URL must start with http:// or https://")

        with get_db() as db:
            product = db.query(ProductModel).filter(ProductModel.id == input.product_id).first()
            if not product:
                raise ValueError("Product not found")

            image = ImageModel(
                product_id=input.product_id,
                url=input.url.strip(),
                alt_text=input.alt_text.strip() if input.alt_text else None,
                sort_order=input.sort_order,
            )
            db.add(image)
            db.commit()
            db.refresh(image)
            return _image_model_to_type(image)

    @strawberry.mutation
    def delete_product(self, id: int) -> bool:
        with get_db() as db:
            product = db.query(ProductModel).filter(ProductModel.id == id).first()
            if not product:
                return False
            db.delete(product)
            db.commit()
            return True


# --- Schema with depth limiting to prevent abuse ---

schema = Schema(
    query=Query,
    mutation=Mutation,
    extensions=[
        QueryDepthLimiter(max_depth=10),
    ],
)


